# Compute best similarity among single, pairs, triples
from difflib import SequenceMatcher

def combined_text(i, k=1):
    # return concatenation of k consecutive ayahs starting at index i
    parts = [qdata[j]['ayah_text'] for j in range(i, min(i+k, len(qdata)))]
    return ' '.join(parts)

def best_combinations(max_k=3):
    best = []
    for k in range(1, max_k+1):
        best_k = (0.0, None, None) # ratio, index, k
        for i in range(len(qdata)):
            if i+k-1 >= len(qdata):
                break
            text = combined_text(i,k)
            ntext = normalize_ar(text)
            ratio = SequenceMatcher(None, input_norm, ntext).ratio()
            if ratio > best_k[0]:
                best_k = (ratio, i, k)
        best.append(best_k)
    return best

